Value.Calculation:
Let([
	ts = GetAsTimestamp ( Get ( CurrentHostTimestamp ) ) ;
	d = GetAsDate ( ts ) ;
	t = GetAsTime ( ts )
] ;
	Year ( d ) & "-" & Right ( "0" & Month ( d ) ; 2 ) & "-" & Right ( "0" & Day ( d ) ; 2 ) & "T" &
	Right ( "0" & Hour ( t ) ; 2 ) & ":" & Right ( "0" & Minute ( t ) ; 2 ) & ":" & Right ( "0" & Int ( Seconds ( t ) ) ; 2 ) & "Z"
)

JSONSetElement ( "{}" ;
[ "vertrag_id" ; JSONGetElement ( $json ; "[" & $idx & "].vertrag_id" ) ; JSONString ] ;
