	own_raw = Lower ( TrimAll ( GetAsText ( JSONGetElement ( $json ; "[" & $idx & "].vertragseigentuemer" ) ) ; 1 ; 1 ) ) ;
	own_norm = Substitute ( own_raw ; "+" ; "-" ; " " ; "-" ; "&" ; "-" ; "/" ; "-" ; "_" ; "-" ) ;
	own_val = Case ( IsEmpty ( own_norm ) or own_norm = "null" ; "unbekannt" ; own_norm )
] ; own_val ) ; JSONString ] ;
