JSONSetElement ( "{}" ;
	[ "script_name" ; "04_FM_ARCHIVY_SYNC_VERTRAEGE_PUSH_EXAKT" ; JSONString ] ;
	[ "script_version" ; $script_version ; JSONString ] ;
	[ "owner_id" ; Lower ( TrimAll ( GetAsText ( $$INHABER_ID ) ; 1 ; 1 ) ) ; JSONString ] ;
	[ "status" ; Case ( IsEmpty ( $fehler ) ; "ok" ; "error" ) ; JSONString ] ;
	[ "ok_count" ; $ok ; JSONNumber ] ;
	[ "skip_count" ; 0 ; JSONNumber ] ;
	[ "error_count" ; Case ( IsEmpty ( $fehler ) ; 0 ; ValueCount ( $fehler ) ) ; JSONNumber ] ;
	[ "result_text" ; Left ( $$SYNC_RESULT_V ; 9000 ) ; JSONString ] ;
	[ "error_text" ; Left ( $fehler ; 9000 ) ; JSONString ] ;
	[ "needs_review" ; True ; JSONBoolean ] ;
	[ "detail_json" ; JSONSetElement ( "{}" ;
		[ "processed_count" ; $anzahl ; JSONNumber ] ;
		[ "table" ; $$FM_VERTRAEGE_TABELLE ; JSONString ]
	) ; JSONObject ]
